func check_level(exp):
    if exp >= 100:
        print("Level Up!")
    else:
        print("Keep fighting!")

func get_damage(atk, def):
    var res = atk - def
    if res < 0:
        return 0
    return res

func _process(delta):
    if Input.is_action_pressed("ui_right"):
        position.x += 5
        if position.x > 500:
            hide()

var direction = 0
func _process(delta):
    if Input.is_action_pressed("ui_left"):
        direction = -1
    elif Input.is_action_pressed("ui_right"):
        direction = 1
    position.x += direction * 10

var bullet_scene = preload("res://bullet.tscn")
func _input(event):
    if event.is_action_pressed("left_click"):
        var b = bullet_scene.instantiate()
        add_child(b)

var can_shoot = true
func shoot():
    if can_shoot:
        can_shoot = false
        $Timer.start()
func _on_timer_timeout():
    can_shoot = true

enum State {IDLE, RUN}
var current_state = State.IDLE
func _process(delta):
    if velocity.x == 0:
        current_state = State.IDLE
    else:
        current_state = State.RUN

signal player_died(pos)
func check_death():
    if hp <= 0:
        player_died.emit(position)

func shake():
    var tween = create_tween()
    tween.tween_property(self, "scale", Vector2(1.2, 1.2), 0.1)
    tween.tween_callback(queue_free)

